<?php
namespace App\Http\Requests\Admin\Content;use App\Domain\WorldCatalog\CatalogStatus;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
class MonsterRequest extends FormRequest{public function authorize(){return true;}public function rules(){$id=$this->route('monster')?$this->route('monster')->id:null;return['code'=>['required','string','max:64',Rule::unique('monsters','code')->ignore($id)],'name'=>'required|string|max:255','description'=>'nullable|string','level'=>'required|integer|min:1','max_health'=>'required|integer|min:1','attack'=>'required|integer|min:0','defense'=>'required|integer|min:0','accuracy_rate'=>'required|numeric|min:0|max:999.99','evasion_rate'=>'required|numeric|min:0|max:999.99','critical_chance'=>'required|numeric|min:0|max:999.99','experience_reward'=>'required|integer|min:0','gold_min'=>'required|integer|min:0','gold_max'=>'required|integer|min:0|gte:gold_min','status'=>['required',Rule::in(CatalogStatus::values())],'image'=>'nullable|file|max:5120|mimetypes:image/png,image/jpeg,image/webp'];}public function messages(){return['image.file'=>'La imagen seleccionada no es un archivo válido.','image.max'=>'La imagen no puede superar 5 MB.','image.mimetypes'=>'Solo se permiten imágenes PNG, JPG o WebP válidas.'];}}
